import base64, os, sys, subprocess, shutil, tempfile

APP_B64 = ""

def main():
    print("=" * 45)
    print("  Installing Haitang Downloader...")
    print("=" * 45)
    print()

    # 临时目录放 D 盘
    tmp = r"D:\\缓存文件\\haitang_build"
    os.makedirs(tmp, exist_ok=True)
    py_path = os.path.join(tmp, "app.py")
    with open(py_path, "wb") as f:
        f.write(base64.b64decode(APP_B64))
    print("[1/3] Ready.")

    print("[2/3] Checking pyinstaller...")
    subprocess.run([sys.executable, "-m", "pip", "install", "pyinstaller", "-q"], check=True)
    print("[2/3] Done.")

    desktop = os.path.join(os.path.expanduser("~"), "Desktop")
    build_dir = os.path.join(tmp, "build")
    print("[3/3] Building exe, please wait 1-2 min...")
    result = subprocess.run([
        sys.executable, "-m", "PyInstaller",
        "--onefile", "--noconsole",
        "--name", "HaitangDownloader",
        "--distpath", desktop,
        "--workpath", build_dir,
        "--specpath", tmp,
        py_path
    ])

    shutil.rmtree(tmp, ignore_errors=True)

    exe = os.path.join(desktop, "HaitangDownloader.exe")
    print()
    print("=" * 45)
    if os.path.exists(exe) and result.returncode == 0:
        print("  Done! HaitangDownloader.exe is on your Desktop.")
        ans = input("  Launch now? (y/n): ").strip().lower()
        if ans == "y":
            os.startfile(exe)
    else:
        print("  Build failed. Please screenshot this and ask for help.")
    print("=" * 45)
    input("Press Enter to close...")

main()
